/**
 * MedX formstate forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Centralized form state store.
 */
const FORMSTATE_TOKENS = Object.freeze({
  primary: { value: "forms-formstate-primary", scope: "forms" },
  secondary: { value: "forms-formstate-secondary", scope: "forms" },
  muted: { value: "forms-formstate-muted", scope: "forms" },
  accent: { value: "forms-formstate-accent", scope: "forms" },
  surface: { value: "forms-formstate-surface", scope: "forms" },
});

const FORMSTATE_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const FORMSTATE_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const formstateRegistry = new Map();
const FORMSTATE_listeners = new Set();
let FORMSTATE_seq = 0;

function createFormstateId(prefix = "medx-forms-formstate") {
  FORMSTATE_seq += 1;
  return `${prefix}-${FORMSTATE_seq}`;
}

function registerFormstate(config = {}) {
  const entryId = config.id ?? createFormstateId();
  const preset = FORMSTATE_PRESETS[config.preset ?? "default"] ?? FORMSTATE_PRESETS.default;
  const token = FORMSTATE_TOKENS[config.token ?? preset.token] ?? FORMSTATE_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: FORMSTATE_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  formstateRegistry.set(entryId, entry);
  notifyFormstateListeners("register", entry);
  return entry;
}

function updateFormstate(id, patch = {}) {
  const entry = formstateRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyFormstateListeners("update", entry);
  return entry;
}

function resolveFormstate(id) {
  const entry = formstateRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listFormstateEntries(filter = {}) {
  let items = Array.from(formstateRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onFormstateEvent(listener) {
  FORMSTATE_listeners.add(listener);
  return () => FORMSTATE_listeners.delete(listener);
}

function notifyFormstateListeners(type, entry) {
  for (const listener of FORMSTATE_listeners) {
    try {
      listener({ type, entry, registrySize: formstateRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:formstate] listener error", err.message);
    }
  }
}

function getFormstateMetrics() {
  const items = listFormstateEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(FORMSTATE_TOKENS).length,
    presets: Object.keys(FORMSTATE_PRESETS).length,
  };
}

async function runMedxFormstate() {
  console.log("[medx:ui:forms:formstate] runtime initialized");
  console.log(`[medx:ui:forms:formstate] tokens=${Object.keys(FORMSTATE_TOKENS).length} presets=${Object.keys(FORMSTATE_PRESETS).length}`);

  const events = [];
  onFormstateEvent((e) => events.push(e.type));

  const domains = Object.keys(FORMSTATE_SUPPLY_CHAIN);
  const presets = Object.keys(FORMSTATE_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerFormstate({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/formstate" },
    });
  }

  const first = listFormstateEntries()[0];
  if (first) updateFormstate(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getFormstateMetrics();
  const resolved = first ? resolveFormstate(first.id) : null;

  console.log(`[medx:ui:forms:formstate] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:formstate] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:formstate] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:formstate] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:formstate] bootstrap complete");
}

module.exports = runMedxFormstate;
